frame_eqs:
wave_a=0;
warp=0;
decay=1;
zoom=1;

bt=bt+bass_att*2/fps;
q1=bt;
tt=tt+treb_att*2/fps;
q2=tt;

q5=aspectx;
q6=aspecty;

sx=1;
dy=-.165;
bbb = bbb*0.99 + bass_att*0.01;
mmm = mmm*0.99 + mid_att*0.01;
ttt = ttt*0.99 + treb_att*0.01;
mx = max(max(bbb,mmm),ttt);
mn = min(min(bbb,mmm),ttt);
t1 = (bbb-mn)/(mx-mn);
t2 = (mmm-mn)/(mx-mn);
t3 = (ttt-mn)/(mx-mn);

v = 0.1/fps;
b1 = b1 + (t1-0.5)*v;
m1 = m1 + (t2-0.5)*v;
tt1 = tt1 + (t3-0.5)*v;
q23 = (b1-tt1);
q24 = -(t1-t2)*0.5;
q25 = (m1-b1)*2;
q26 = 0.3+(t1-t2)*0.09;
q27 = 0.25;


q29=.3 + bass_att/8;
rot=bass_att/5*sin(time*9999);
dx=sin(time);
dy=cos(time);

wave_0_per_point:
n=sample*6.283;
phs=-sample * 0.2;
tm=q1 + phs;

flip=flip+1;
flip=flip*below(flip,2);

xp=0;
yp=flip*0.1 + (sin(tm)*0.5 + 0.5)*0.2;
zp=0;

//wrist movement;
ang=sin(tm*2)*0.5 +0.5;

xq=xp;
sinang=sin(ang);cosang=cos(ang);
yq=yp*sinang + zp*cosang;
zq=yp*cosang - zp*sinang;
yq=yp;
zq=zp;

ang=tm*8;
sinang=sin(ang);cosang=cos(ang);
xp=xq*sinang + yq*cosang;
yp=xq*cosang - yq*sinang;
zp=zq;

//forearm movement;
zp=zp-0.3;
ang=3.14 + sin(tm*2 - 0.5)*1.5;
sinang=sin(ang);cosang=cos(ang);
xq=xp;
yq=yp*sinang + zp*cosang;
zq=yp*cosang - zp*sinang;

//upper arm twist
ang=-1.0 + cos(tm*3.1 + 0.5);
sinang=sin(ang);cosang=cos(ang);
xp=xq*sinang + yq*cosang;
yp=xq*cosang - yq*sinang;
zp=zq;

//upper arm outward;
zp=zp-0.35;
ang=cos(tm*2.3)*1.75 - 1.05;
sinang=sin(ang);cosang=cos(ang);
xq=xp*sinang + zp*cosang;
yq=yp;
zq=xp*cosang - zp*sinang;

//upper arm up down;
ang=cos(tm)*0.5 - 0.5;
sinang=sin(ang);cosang=cos(ang);
xp=xq;
yp=yq*cosang - zq*sinang;
zp=yq*sinang + zq*cosang;

//xp=xq;yp=yq;zp=zq;


//project into screenspace and draw on screen
zp=zp+2;
xs=xp/zp;
ys=yp/zp;

x=xs+0.5;
y=ys*1.3+0.5;


a=(1-sample);

b=b+pow(1-sample,2)*0.3;



r1=t1;
g1=t2;
b1=t3;
r2=t4;
g2=t5;
b2=t6;

r=r1*flip + r2*(1-flip);
g=g1*flip + g2*(1-flip);
b=b1*flip + b2*(1-flip);

